import Empty from '@/components/empty/empty';
import { RenameDialog } from '@/components/rename-dialog';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuCheckboxItem,
  DropdownMenuContent,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { SearchInput } from '@/components/ui/input';
import { RAGFlowPagination } from '@/components/ui/ragflow-pagination';
import { PermissionRole } from '@/constants/permission';
import { useFetchNextKnowledgeListByPage } from '@/hooks/use-knowledge-request';
import { cn } from '@/lib/utils';
import { formatDate } from '@/utils/date';
import { pick } from 'lodash';
import { ListFilter, Plus } from 'lucide-react';
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { DatasetCreatingDialog } from './dataset-creating-dialog';
import { useSaveKnowledge } from './hooks';
import { useRenameDataset } from './use-rename-dataset';
import { useSelectOwners } from './use-select-owners';
//----
import { MoreButton } from '@/components/more-button';
import { RAGFlowAvatar } from '@/components/ragflow-avatar';
import { useNavigatePage } from '@/hooks/logic-hooks/navigate-hooks';
import { IKnowledge } from '@/interfaces/database/knowledge';
import type { TableProps } from 'antd';
import { Table } from 'antd';
import dayjs from 'dayjs';
import { DatasetDropdown } from './dataset-dropdown';
import styles from './index.less';

interface DataType {
  key: string;
  knowledgeName: string;
  ownerName: string;
  permission: string;
  file_count: number;
  chunk_count: number;
  edit_time: string;
  edit_time_value: number;
  avatar?: string | null;
  dataset?: IKnowledge;
}

export default function Datasets() {
  const { t } = useTranslation();
  const tableCardRef = useRef<HTMLDivElement>(null);
  const [tableScrollY, setTableScrollY] = useState(320);
  const numberFormatter = useMemo(() => new Intl.NumberFormat(), []);
  const {
    visible,
    hideModal,
    showModal,
    onCreateOk,
    loading: creatingLoading,
  } = useSaveKnowledge();

  const {
    kbs,
    total,
    loading,
    pagination,
    setPagination,
    handleInputChange,
    searchString,
    filterValue,
    handleFilterSubmit,
  } = useFetchNextKnowledgeListByPage();

  const owners = useSelectOwners();
  const ownerFilters =
    owners.find((item) => item.field === 'owner')?.list ?? [];
  const selectedOwnerIds = filterValue.owner ?? [];
  const ownerFilterIds = ownerFilters.map((item) => item.id);

  const { navigateToDataset } = useNavigatePage();

  const {
    datasetRenameLoading,
    initialDatasetName,
    onDatasetRenameOk,
    datasetRenameVisible,
    hideDatasetRenameModal,
    showDatasetRenameModal,
  } = useRenameDataset();

  const handlePageChange = useCallback(
    (page: number, pageSize?: number) => {
      setPagination({ page, pageSize });
    },
    [setPagination],
  );

  const handleOwnerFilterChange = useCallback(
    (nextOwnerIds: string[]) => {
      handleFilterSubmit({
        ...filterValue,
        owner: nextOwnerIds,
      });
    },
    [filterValue, handleFilterSubmit],
  );

  const columns: TableProps<DataType>['columns'] = [
    {
      title: t('knowledgeList.name'),
      dataIndex: 'knowledgeName',
      key: 'knowledgeName',
      width: 320,
      render: (_, record) => (
        <div className={styles.nameCell}>
          <RAGFlowAvatar
            className="w-[28px] h-[28px]"
            avatar={record.avatar ?? undefined}
            name={record.knowledgeName}
          />
          <button
            type="button"
            className={styles.nameButton}
            onClick={(e) => {
              e.stopPropagation();
              navigateToDataset(record.key)();
            }}
          >
            {record.knowledgeName}
          </button>
        </div>
      ),
    },
    {
      title: t('knowledgeList.owner'),
      dataIndex: 'ownerName',
      key: 'ownerName',
      width: 160,
      render: (value: string) => value || '-',
    },
    {
      title: t('knowledgeConfiguration.permissions'),
      dataIndex: 'permission',
      key: 'permission',
      width: 140,
      render: (permission: string) => {
        const isTeam = permission === PermissionRole.Team;
        return (
          <span
            className={cn(
              styles.badgeBase,
              isTeam ? styles.teamPermissionBadge : styles.mePermissionBadge,
            )}
          >
            {isTeam
              ? t('knowledgeConfiguration.team')
              : t('knowledgeConfiguration.me')}
          </span>
        );
      },
    },
    {
      title: t('fileManager.files'),
      dataIndex: 'file_count',
      key: 'file_count',
      width: 120,
      sorter: (a, b) => a.file_count - b.file_count,
      sortDirections: ['descend', 'ascend'],
    },
    {
      title: t('knowledgeDetails.chunkNumber'),
      dataIndex: 'chunk_count',
      key: 'chunk_count',
      width: 130,
      sorter: (a, b) => a.chunk_count - b.chunk_count,
      sortDirections: ['descend', 'ascend'],
    },
    {
      title: t('knowledgeList.modifiedTime'),
      dataIndex: 'edit_time',
      key: 'edit_time',
      width: 180,
      sorter: (a, b) => a.edit_time_value - b.edit_time_value,
      sortDirections: ['descend', 'ascend'],
    },
    {
      title: t('common.action'),
      key: 'action',
      width: 80,
      align: 'center',
      render: (_, record) => (
        <div
          onClick={(e) => {
            e.stopPropagation();
          }}
        >
          <DatasetDropdown
            showDatasetRenameModal={showDatasetRenameModal}
            dataset={record.dataset!}
          >
            <MoreButton className={styles.actionButton} />
          </DatasetDropdown>
        </div>
      ),
    },
  ];

  const data: DataType[] = (kbs || []).map((kb) => ({
    key: kb.id,
    knowledgeName: kb.name || '',
    ownerName: kb.nickname || '-',
    permission: kb.permission || PermissionRole.Me,
    file_count: kb.doc_num ?? 0,
    chunk_count: kb.chunk_num ?? 0,
    avatar: (kb as any).avatar ?? null,
    edit_time: kb.update_time ? formatDate(kb.update_time) : '',
    edit_time_value:
      Number(kb.update_time ?? 0) > 10 ** 12
        ? Number(kb.update_time ?? 0)
        : Number(kb.update_time ?? 0) * 1000,
    dataset: kb,
  }));

  const stats = useMemo(() => {
    const datasets = kbs || [];
    const lastSevenDaysStart = dayjs().subtract(7, 'day').valueOf();

    const fileTotalOnPage = datasets.reduce(
      (sum, item) => sum + (item.doc_num || 0),
      0,
    );
    const tokenTotalOnPage = datasets.reduce(
      (sum, item) => sum + (item.token_num || 0),
      0,
    );
    const recentlyUpdatedOnPage = datasets.filter(
      (item) =>
        (Number(item.update_time ?? 0) > 10 ** 12
          ? Number(item.update_time ?? 0)
          : Number(item.update_time ?? 0) * 1000) >= lastSevenDaysStart,
    ).length;

    return [
      {
        label: t('knowledgeList.totalDatasets'),
        value: numberFormatter.format(total || 0),
      },
      {
        label: t('knowledgeList.totalFilesOnPage'),
        value: numberFormatter.format(fileTotalOnPage),
      },
      {
        label: t('knowledgeList.totalTokensOnPage'),
        value: numberFormatter.format(tokenTotalOnPage),
      },
      {
        label: t('knowledgeList.recentlyUpdatedOnPage'),
        value: numberFormatter.format(recentlyUpdatedOnPage),
        description: t('knowledgeList.last7Days'),
      },
    ];
  }, [kbs, numberFormatter, t, total]);

  useEffect(() => {
    const el = tableCardRef.current;
    if (!el) {
      return;
    }

    const updateTableScrollY = () => {
      const availableHeight = el.clientHeight;
      // Keep a stable minimum while reserving header height.
      const nextY = Math.max(180, Math.floor(availableHeight - 52));
      setTableScrollY(nextY);
    };

    updateTableScrollY();
    const observer = new ResizeObserver(updateTableScrollY);
    observer.observe(el);
    window.addEventListener('resize', updateTableScrollY);

    return () => {
      observer.disconnect();
      window.removeEventListener('resize', updateTableScrollY);
    };
  }, []);

  const NewTable: React.FC = () => (
    <Table<DataType>
      columns={columns}
      dataSource={data}
      pagination={false}
      loading={loading}
      rowKey={'key'}
      sticky
      scroll={{ x: 'max-content', y: tableScrollY }}
      locale={{ emptyText: <Empty className="py-8" /> }}
      className={styles.datasetTable}
      onRow={(record) => ({
        onClick: navigateToDataset(record.key),
      })}
    />
  );

  return (
    <section className={styles.page}>
      <div className={styles.filterRow}>
        <div className={styles.filterControls}>
          <SearchInput
            value={searchString}
            onChange={handleInputChange}
            className={styles.searchInput}
            placeholder={t('knowledgeDetails.searchByName', {
              defaultValue: '输入知识库名称搜索',
            })}
          />
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                variant="transparent"
                className={styles.ownerFilterButton}
              >
                {t('knowledgeList.owner', { defaultValue: '所有者' })}
                {selectedOwnerIds.length > 0
                  ? ` (${selectedOwnerIds.length})`
                  : ''}
                <ListFilter className="size-3.5" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="start" className="w-56 p-1.5">
              <DropdownMenuLabel className="px-2 py-1 text-xs text-[#9ca3af]">
                {t('knowledgeList.owner', { defaultValue: '所有者' })}
              </DropdownMenuLabel>
              <DropdownMenuSeparator />
              <DropdownMenuCheckboxItem
                checked={
                  ownerFilterIds.length > 0 &&
                  selectedOwnerIds.length === ownerFilterIds.length
                }
                onSelect={(event) => event.preventDefault()}
                onCheckedChange={(checked) =>
                  handleOwnerFilterChange(checked ? ownerFilterIds : [])
                }
                className="py-2"
              >
                {t('common.selectAll', { defaultValue: '全选' })}
              </DropdownMenuCheckboxItem>
              {ownerFilters.map((item) => (
                <DropdownMenuCheckboxItem
                  key={item.id}
                  checked={selectedOwnerIds.includes(item.id)}
                  onSelect={(event) => event.preventDefault()}
                  onCheckedChange={(checked) => {
                    const next = checked
                      ? [...selectedOwnerIds, item.id]
                      : selectedOwnerIds.filter((x) => x !== item.id);
                    handleOwnerFilterChange(Array.from(new Set(next)));
                  }}
                  className="py-2"
                >
                  <span className="inline-flex items-center justify-between w-full pr-1">
                    <span>{item.label}</span>
                    <span className="text-xs text-[#9ca3af]">{item.count}</span>
                  </span>
                </DropdownMenuCheckboxItem>
              ))}
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
        <div className={styles.toolbarActions}>
          <Button onClick={showModal} className={styles.primaryActionButton}>
            <Plus className="size-3.5" />
            {t('knowledgeList.createKnowledgeBase')}
          </Button>
        </div>
      </div>
      <div className={styles.statsGrid}>
        {stats.map((item) => (
          <article key={item.label} className={styles.statCard}>
            <div className={styles.statLabel}>{item.label}</div>
            <div className={styles.statValue}>{item.value}</div>
            {item.description ? (
              <div className={styles.statDescription}>{item.description}</div>
            ) : null}
          </article>
        ))}
      </div>
      <div className={styles.tableCard} ref={tableCardRef}>
        <NewTable />
      </div>
      <div className={styles.tablePagination}>
        <RAGFlowPagination
          {...pick(pagination, 'current', 'pageSize')}
          total={total}
          onChange={handlePageChange}
        ></RAGFlowPagination>
      </div>
      {visible && (
        <DatasetCreatingDialog
          hideModal={hideModal}
          onOk={onCreateOk}
          loading={creatingLoading}
        ></DatasetCreatingDialog>
      )}
      {datasetRenameVisible && (
        <RenameDialog
          hideModal={hideDatasetRenameModal}
          onOk={onDatasetRenameOk}
          initialName={initialDatasetName}
          loading={datasetRenameLoading}
        ></RenameDialog>
      )}
    </section>
  );
}
